		wp_fusion()->crm->connect(); // Set up the Infusionsoft API

		$result = wp_fusion()->crm->app->loadCon( $contact_id, array( 'ContactNotes' ) ); // Load the contact

		if ( ! is_wp_error( $result ) && ! empty( $result['ContactNotes'] ) ) {

